SELECT count(*) FROM title, movie_companies, kind_type, company_type, company_name, movie_info, movie_keyword, info_type WHERE movie_companies.movie_id = title.id AND title.kind_id = kind_type.id AND movie_companies.company_type_id = company_type.id AND movie_companies.company_id = company_name.id AND movie_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_info.info_type_id = info_type.id;